// SPDX-License-Identifier: MIT

pragma solidity >=0.8.3;

import "./NewsValidationLib.sol";

contract NewsManager {

    // CUSTOM ERRORS
    // Admin
    error OnlyOwner();

    // Validators
    error ValidatorNotFound();
    error ValidatorAlreadyExists();
    error ValidatorNotActive();

    // News
    error NewsNotFound();
    error NewsExpired();
    error NewsNotConfirmed();
    error AlreadyValidated();

    // Rating
    error InvalidRating(uint8 _vote);

    // Reward Pool
    error InsufficientBalance(uint256 available, uint256 required);
    

    // STRUCTS
    struct Validator {
        uint256 accumulatedRewards;
        uint256 totalVotes;
        uint256 sumOfRatings;
        bool isActive;
    }

    struct News {
        address createBy;
        string newsName;
        uint256 deadline;
        uint256 minValidations;
        bool isConfirmed;
        uint256 validationCount;
        address[] validators;
    }

    // STATE VARIABLES
    address public owner;
    uint256 public totalDistributed;
    uint256 public rewardAmount;

    // MAPPINGS
    mapping(address => Validator) public validators;
    mapping(address => News) public newsList;
    
    // ARRAYS
    address[] validatorsList;
}

NewsValidationLib.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity >=0.8.3;

library NewsValidationLib {
    function getValidatorsCount(address[] storage _validators) internal view returns (uint256) {
        return _validators.length;
    }

    function isValidator(address[] storage _validators, address _target) internal view returns (bool) {
        for (
            uint256 i = 0; i < _validators.length; i++
        ) {
            if (_validators[i] == _target) return true;
        }
        return false;
    }

    function isNewsConfirmed(
        uint256 validationCount,
        uint256 minValidations,
        bool isConfirmed
    ) internal pure returns (bool) {
        return validationCount >= minValidations && isConfirmed;
    }
}

